List<List<int>> generatePermutations(List<int> list) {
  // Base case: if the list has only one element, return a list containing that element
  if (list.length == 1) {
    return [list];
  }

  // Initialize an empty list to store all permutations
  List<List<int>> permutations = [];

  // Iterate over each element in the list
  for (int i = 0; i < list.length; i++) {
    // Remove the current element
    int currentElement = list[i];
    List<int> remainingElements = List.from(list)..removeAt(i);

    // Generate all permutations of the remaining elements
    List<List<int>> remainingPermutations = generatePermutations(remainingElements);

    // Prepend the current element to each of the remaining permutations
    for (List<int> permutation in remainingPermutations) {
      permutations.add([currentElement, ...permutation]);
    }
  }

  return permutations;
}

