int passBallGame(int n, int m) {
  // Create a 2D list dp with dimensions (m + 1) x (n + 1)
  List<List<int>> dp = List.generate(m + 1, (_) => List.filled(n + 1, 0));

  // Base case: no passes, ball is with student 1
  dp[0][1] = 1;

