List<int> calculateNewDigits(int N, int M, List<int> digits) {
  // Helper function to calculate factorial
  int factorial(int n) {
    if (n == 0 || n == 1) return 1;
    int result = 1;
    for (int i = 2; i <= n; i++) {
      result *= i;
    }
    return result;
  }

