  // Helper function to calculate factorial
  int factorial(int n) {
    if (n == 0 || n == 1) return 1;
    int result = 1;
    for (int i = 2; i <= n; i++) {
      result *= i;
    }
    return result;
  }

  // Helper function to convert permutation to number
  int permutationToNumber(List<int> perm) {
    int number = 0;
    List<int> available = List.from(perm);
    for (int i = 0; i < perm.length; i++) {
      int index = available.indexOf(perm[i]);
      number += index * factorial(perm.length - i - 1);
      available.removeAt(index);
    }
    return number;
  }

