int minimumUntidiness(List<Book> books, int k) {
  int n = books.length;
  if (k == n) return 0; // If we remove all books, untidiness is 0

  // Sort books by width
  books.sort((a, b) => a.width.compareTo(b.width));

  // Calculate initial untidiness
  int initialUntidiness = 0;
