String removeKDigits(String num, int k) {
  if (num.length <= k) {
    return "0";
  }

  List<String> stack = [];

  for (int i = 0; i < num.length; i++) {
    while (k > 0 && stack.isNotEmpty && stack.last.compareTo(num[i]) > 0) {
